UPDATE courses
SET hero_subheading = '<span class="block">Our SAP IBP Training aims to equip professionals with the skills to effectively and efficiently optimize end-to-end supply chain processes with SAP Integrated Business Planning (IBP). Through hands-on, live sessions, you will acquire skills in demand planning, supply planning, inventory optimization and sales and operations planning (S&OP) using IBP.</span><span class="hidden md:block mt-4">This SAP IBP course covers real-world scenarios and practical exercises, providing the essential knowledge you need to configure planning models, generate forecasts, manage alerts and generate actionable insights that facilitate effective decision-making. Perfect for supply chain professionals, planners and consultants seeking SAP IBP certification as well as those looking to increase efficiency, collaboration and performance within their organizations'' supply chains, this training equips learners to drive efficiency, collaboration and performance across their supply chains.</span>'
WHERE id = 'sap-ibp';
